def build_pipeline_jdbc_config() -> dict:
    def _url(host_env: str, port_env: str, db_env: str, host_d: str, port_d: str, db_d: str) -> str:
        h = os.environ.get(host_env, host_d)
        p = os.environ.get(port_env, port_d)
        d = os.environ.get(db_env,  db_d)
        return (f"jdbc:sqlserver://{h}:{p};databaseName={d};"
                "encrypt=true;trustServerCertificate=true")

    return {
        "source_url": _url("SOURCE_DB_HOST", "SOURCE_DB_PORT", "SOURCE_DB_NAME",
                           "source-server", "1433", "SourceDB"),
        "target_url": _url("TARGET_DB_HOST", "TARGET_DB_PORT", "TARGET_DB_NAME",
                           "target-server", "1433", "TargetDB"),
        "npi_url":    _url("NPI_DB_HOST",    "NPI_DB_PORT",    "NPI_DB_NAME",
                           "target-server",  "1433", "TargetDB"),  # npi_registry lives in TargetDB
        "driver":   "com.microsoft.sqlserver.jdbc.SQLServerDriver",
        "user":     os.environ.get("ETL_DB_USER",     ""),  # TODO: dbutils.secrets.get(...)
        "password": os.environ.get("ETL_DB_PASSWORD", ""),  # TODO: dbutils.secrets.get(...)
    }


