def transform_gender_standardization(input_df: DataFrame) -> DataFrame:
    try:
        norm = F.upper(F.trim(F.col("gender")))
        expr = (
            F.when(F.col("gender").isNull() | (norm == "U") | (norm == "UNKNOWN"), F.lit("U"))
             .when((norm == "M") | (norm == "MALE"),   F.lit("M"))
             .when((norm == "F") | (norm == "FEMALE"), F.lit("F"))
             .otherwise(F.lit("Other"))
        )
        return input_df.withColumn("gender_standardized", expr)
    except Exception as e:
        logger.error("transform_gender_standardization failed: %s", e, exc_info=True)
        raise


def transform_zip_code_standardization(input_df: DataFrame) -> DataFrame:
    try:
        df = input_df.withColumn(
            "_zip_cleaned",
            F.regexp_replace(F.regexp_replace(F.trim(F.col("zip_code")), "-", ""), " ", ""),
        )
        df = df.withColumn(
            "zip_code_standardized",
            F.when(
                F.length(F.col("_zip_cleaned")) == 9,
                F.concat(
                    F.substring(F.col("_zip_cleaned"), 1, 5),
                    F.lit("-"),
                    F.substring(F.col("_zip_cleaned"), 6, 4),
                ),
            ).when(
                F.length(F.col("_zip_cleaned")) >= 5,
                F.substring(F.col("_zip_cleaned"), 1, 5),
            ).otherwise(
                F.lpad(F.col("_zip_cleaned"), 5, "0"),
            ),
        ).drop("_zip_cleaned")
        return df
    except Exception as e:
        logger.error("transform_zip_code_standardization failed: %s", e, exc_info=True)
        raise


def validate_member_data(df: DataFrame) -> DataFrame:
    try:
        total = df.count()
        null_df = df.filter(F.col("member_id").isNull()).withColumn(
            "_error_reason", F.lit("member_id is NULL")
        ).withColumn("_error_timestamp", F.current_timestamp())
        null_count = null_df.count()
        if null_count > 0:
            logger.warning("validate_member_data: %d/%d rows have NULL member_id", null_count, total)
            null_df.write.mode("append").saveAsTable("error.silver_member_rejects")
        dup_count = df.groupBy("member_id").count().filter(F.col("count") > 1).count()
        if dup_count > 0:
            logger.warning("validate_member_data: %d duplicate member_id values", dup_count)
        valid_df = df.filter(F.col("member_id").isNotNull())
        logger.info("validate_member_data: %d valid / %d rejected", valid_df.count(), null_count)
        return valid_df
    except Exception as e:
        logger.error("validate_member_data failed: %s", e, exc_info=True)
        raise


def run_dft_transform_members(spark: SparkSession) -> int:
    try:
        logger.info("[DFT_TransformMembers] START")
        raw_df = spark.table("bronze.member")

        df = transform_gender_standardization(raw_df)
        df = transform_zip_code_standardization(df)
        df = validate_member_data(df)

        # Destination column projection — only SSIS-mapped columns written
        write_df = df.select(
            "member_id", "mrn", "first_name", "last_name", "date_of_birth",
            "gender", "race", "ethnicity",
            "address_line1", "city", "state", "zip_code",
            "phone", "email", "death_date",
            "created_timestamp", "updated_timestamp",
            F.col("gender_standardized"),
            F.col("zip_code_standardized"),
        )
        write_df.write.mode("overwrite").option("overwriteSchema", "true").saveAsTable(
            "silver.member_transformed"
        )
        row_count = write_df.count()
        logger.info("[DFT_TransformMembers] completed: %d rows → silver.member_transformed", row_count)
        return row_count
    except Exception as e:
        logger.error("[DFT_TransformMembers] FAILED: %s", e, exc_info=True)
        raise


