def lookup_provider_npi(input_df: DataFrame, spark: SparkSession, jdbc_config: dict) -> DataFrame:
    try:
        # Rule S-LKP-1: npi_registry lives in TargetDB → use npi_url
        lookup_url = jdbc_config.get("npi_url") or jdbc_config.get("target_url", "")

        npi_sql = """(
            SELECT
                npi,
                CONCAT(
                    provider_organization_name,
                    COALESCE(CONCAT(' - ', provider_first_name, ' ', provider_last_name), '')
                ) AS provider_name_standardized,
                entity_type_code AS provider_type,
                healthcare_provider_taxonomy_code_1 AS taxonomy_code
            FROM dbo.npi_registry
            WHERE npi IS NOT NULL
        ) AS npi_ref"""

        npi_df = (
            spark.read.format("jdbc")
            .option("url",      lookup_url)
            .option("dbtable",  npi_sql)
            .option("driver",   jdbc_config["driver"])
            .option("user",     jdbc_config["user"])
            .option("password", jdbc_config["password"])
            .load()
            .cache()
        )

        npi_broadcast = F.broadcast(npi_df)

        matched_df = (
            input_df.alias("c")
            .join(npi_broadcast.alias("n"),
                  F.col("c.provider_npi").eqNullSafe(F.col("n.npi")), "inner")
            .select(
                F.col("c.*"),
                F.col("n.provider_name_standardized"),
                F.col("n.provider_type"),
                F.col("n.taxonomy_code"),
            )
        )

        unmatched_df = (
            input_df.alias("c")
            .join(npi_broadcast.alias("n"),
                  F.col("c.provider_npi").eqNullSafe(F.col("n.npi")), "left_anti")
            .withColumn("provider_name_standardized", F.lit(None).cast(StringType()))
            .withColumn("provider_type",              F.lit(None).cast(StringType()))
            .withColumn("taxonomy_code",              F.lit(None).cast(StringType()))
        )

        matched_count   = matched_df.count()
        unmatched_count = unmatched_df.count()
        logger.info("LKP_ProviderNPI: matched=%d unmatched=%d", matched_count, unmatched_count)
        if unmatched_count > 0:
            logger.warning("LKP_ProviderNPI: %d claims have no NPI registry match", unmatched_count)

        result_df = matched_df.unionByName(unmatched_df)
        npi_df.unpersist()
        return result_df
    except Exception as e:
        logger.error("lookup_provider_npi failed: %s", e, exc_info=True)
        raise


def transform_der_claim_type(input_df: DataFrame) -> DataFrame:
    try:
        cond_freq_orig    = F.col("claim_frequency") == F.lit("1")
        cond_freq_replace = F.col("claim_frequency") == F.lit("7")
        # Lexicographic CPT range — faithfully replicates SSIS string comparison
        cond_cpt = (
            (F.substring(F.col("procedure_code1"), 1, 2) >= F.lit("99")) &
            (F.substring(F.col("procedure_code1"), 1, 5) <= F.lit("99223"))
        )
        is_inpatient_expr = cond_freq_orig | cond_freq_replace | cond_cpt

        df = input_df.withColumn(
            "is_inpatient",
            F.when(is_inpatient_expr, True).otherwise(False).cast(BooleanType()),
        ).withColumn(
            "claim_year",
            F.year(F.col("service_date_start")).cast(IntegerType()),
        )
        return df
    except Exception as e:
        logger.error("transform_der_claim_type failed: %s", e, exc_info=True)
        raise


