def transform_ndc_standardization(input_df: DataFrame) -> DataFrame:
    try:
        # SSIS: RIGHT("00000000000" + REPLACE(REPLACE(REPLACE(TRIM(ndc_code),"-","")," ",""),"*",""), 11)
        cleaned = F.regexp_replace(F.trim(F.col("ndc_code")), r"[-\s*]", "")
        ndc_11  = F.lpad(cleaned, 11, "0")

        df = input_df.withColumn("ndc_code_standardized", ndc_11)
        df = df.withColumn(
            "ndc_formatted",
            F.concat(
                F.substring(F.col("ndc_code_standardized"), 1,  5), F.lit("-"),
                F.substring(F.col("ndc_code_standardized"), 6,  4), F.lit("-"),
                F.substring(F.col("ndc_code_standardized"), 10, 2),
            ),
        )
        df = df.withColumn("rx_year", F.year(F.col("fill_date")).cast(IntegerType()))
        return df
    except Exception as e:
        logger.error("transform_ndc_standardization failed: %s", e, exc_info=True)
        raise


