# =============================================================================
# SECTION 4 — Silver Pipeline Orchestrator
# =============================================================================

def run_silver_pipeline(
    spark: SparkSession,
    processing_date: Optional[str] = None,
    jdbc_config: Optional[dict] = None,
    task_filter: Optional[str] = None,
    batch_identifier: Optional[str] = None,
    batch_id: Optional[int] = None,
    batch_run_id: Optional[int] = None,
) -> dict:
    global EXTRACT_COUNT, ERROR_COUNT, LOAD_COUNT

    if jdbc_config is None:
        jdbc_config = build_pipeline_jdbc_config()

    start_time = datetime.now()
    logger.info("=" * 70)
    logger.info("Silver Pipeline START  processing_date=%s  filter=%s", processing_date, task_filter)
    logger.info("=" * 70)

    results: dict = {}

    # ── Phase 1: DFT_TransformMembers (must complete before claims/pharmacy) ──
    run_members  = not task_filter or "members"  in task_filter.lower()
    run_claims   = not task_filter or "claims"   in task_filter.lower()
    run_pharmacy = not task_filter or "pharmacy" in task_filter.lower()

    # Members must run first (precedence constraint)
    if run_members:
        count = run_dft_transform_members(spark)
        results["members"] = count
        EXTRACT_COUNT += count
        logger.info("User::RowCount_Members = %d", count)

    # Claims and Pharmacy can run in parallel after Members
    parallel_tasks = {}
    if run_claims:
        parallel_tasks["claims"] = lambda: run_dft_transform_claims(spark, jdbc_config)
    if run_pharmacy:
        parallel_tasks["pharmacy"] = lambda: run_dft_transform_pharmacy(spark)

    if parallel_tasks:
        with ThreadPoolExecutor(max_workers=len(parallel_tasks)) as executor:
            futures = {executor.submit(fn): name for name, fn in parallel_tasks.items()}
            for future in as_completed(futures):
                name = futures[future]
                try:
                    count = future.result()
                    results[name] = count
                    EXTRACT_COUNT += count
                    if name == "claims":
                        logger.info("User::RowCount_Claims = %d", count)
                    elif name == "pharmacy":
                        logger.info("User::RowCount_Pharmacy = %d", count)
                except Exception as exc:
                    logger.error("Phase 1 task '%s' FAILED: %s", name, exc, exc_info=True)
                    raise

    LOAD_COUNT  = EXTRACT_COUNT - ERROR_COUNT
    elapsed     = datetime.now() - start_time

    logger.info("=" * 70)
    logger.info(
        "Silver Pipeline COMPLETE  elapsed=%s  extract=%d  errors=%d  loaded=%d",
        str(elapsed), EXTRACT_COUNT, ERROR_COUNT, LOAD_COUNT,
    )
    logger.info("=" * 70)

    results.update({
        "extract_count": EXTRACT_COUNT,
        "error_count":   ERROR_COUNT,
        "load_count":    LOAD_COUNT,
    })
    return results


